parameters.jsCode:
// Get webhook data
const replyBodyHtml = $('Webhook').item.json.body.reply_body || '';
const sentMessageText = $('Webhook').item.json.body.sent_message.text || '';
const latestReply = $('Webhook').item.json.body.preview_text || '';
const leadName = $('Webhook').item.json.body.to_name || 'Lead';
const CompanyName = $('HTTP get lead data').item.json.company_name || 'Unknown Company';const leadEmail = $('Webhook').item.json.body.to_email || 'Unknown Email';
const replyDate = $('Webhook').item.json.body.time_replied 
  ? new Date($('Webhook').item.json.body.time_replied).toLocaleString('en-GB', { timeZone: 'Europe/Paris', year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' })
  : 'Unknown Date';

// Clean text function
function clean(text) {
  return text
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&quot;/g, '"')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

// Extract ALL messages - ИСПРАВЛЕННОЕ регулярное выражение
const allMessages = [];

// Попробуем найти любые div-ы (с dir="ltr" или без)
const matches = replyBodyHtml.match(/<div[^>]*>([^<]*(?:<[^>]+>[^<]*)*?)<\/div>/gi);

if (matches) {
  matches.forEach(match => {
    const text = clean(match);
    if (text && 
        text.length > 5 && 
        !text.toLowerCase().includes('petr') && 
        !text.toLowerCase().includes('cpo') && 
        !text.toLowerCase().includes('sally') &&
        !text.includes('https://')) {
      if (!allMessages.includes(text)) {
        allMessages.push(text);
      }
    }
  });
}

// FALLBACK: если allMessages пустой, добавляем хотя бы latestReply
if (allMessages.length === 0 && latestReply) {
  allMessages.push(clean(latestReply));
}

// Build conversation for OpenAI (plain text, no HTML)
let conversationForOpenAI = 
  `Date: ${replyDate}\n` + 
  `Company: ${CompanyName}\n` + 
  `Lead: ${leadName}\n` + 
  `Email: ${leadEmail}\n` + 
  `Latest Reply:\n${clean(latestReply)}\n\n`;

if (allMessages.length > 1) {
  conversationForOpenAI += `Previous Messages:\n`;
  for (let i = 1; i < allMessages.length; i++) {
    conversationForOpenAI += `${leadName}: ${allMessages[i]}\n`;
  }
}

conversationForOpenAI += `\nYour First Message:\n${clean(sentMessageText)}`;

// Return EVERYTHING needed for downstream nodes
return [{
  json: {
    // For OpenAI
    conversation_for_openai: conversationForOpenAI,
    full_conversation_text: conversationForOpenAI,

    // Для Slack и следующих шагов
    allMessages: allMessages, // Теперь ТОЧНО будет массив
    latestReply: latestReply,
    leadName: leadName,
    sentMessageText: sentMessageText,

    // Debug info
    debug_allMessages_length: allMessages.length,
    debug_replyBodyHtml: replyBodyHtml
  }
}];

