const t = $json.time_replied || ($('Webhook').item.json.body && $('Webhook').item.json.body.time_replied);
const dateParis = t ? new Date(t).toLocaleString('en-GB', {
    timeZone: 'Europe/Paris',
    month: 'short',
    day: 'numeric',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
}) : 'no time';
return {
    ...$json,
    formatted_time: dateParis
}

const parsedData = $('Parse Conversation').item.json;
const latestReply = parsedData.latest_reply || parsedData.latestReply || '';
const allMessages = parsedData.allMessages || [];
const leadName = parsedData.lead_name || parsedData.leadName || 'Lead';
const sentMessageText = parsedData.sent_message_text || parsedData.sentMessageText || '';

function clean(text) {
  return (text || '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&quot;/g, '"')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

const recentCount = 5;
let slackRecent = '';

if (Array.isArray(allMessages) && allMessages.length > 0) {
  slackRecent += `📧 *Latest reply from ${leadName}:*\n${clean(latestReply)}\n\n`;

  // Берем ПЕРВЫЕ recentCount сообщений после index 0 (самые свежие)
  if (allMessages.length > 1) {
    slackRecent += `💬 *Recent messages:*\n`;
    const endIndex = Math.min(1 + recentCount, allMessages.length);

    for (let i = 1; i < endIndex; i++) {
      slackRecent += `• ${clean(allMessages[i])}\n`;
    }
  }

  slackRecent += `\n📤 *Your first message:*\n${clean(sentMessageText)}`;
} else {
  slackRecent = `📧 *Latest reply:*\n${clean(latestReply)}`;
}

return [{
  json: {
    ...parsedData,
    slack_recent_conversation: slackRecent
  }
}];

function markdownToSlack(text) {
  // 1. Подмена крупных заголовков: "--- ... ---" -> "\n====== ... ======\n"
  text = text.replace(/-+ ?(.+?) ?-+/g, '\n====== $1 ======\n');
  // 2. Подмена markdown-заголовков через "# ..." -> "\n====== ... ======\n"
  text = text.replace(/^#+\s*(.+)$/gm, '\n====== $1 ======\n');
  // 3. Снятие курсив/жирный, оставить только обрамление звездочками для жирного
  text = text.replace(/\*\*(.+?)\*\*/g, '*$1*');   // жирный
  text = text.replace(/\*(.+?)\*/g, '$1');         // убрать курсив
  // 4. Списки: любой "- ..." или "* ..." переводить в Slack-style буллет
  text = text.replace(/^\s*[-*]\s*/gm, '• ');
  // 5. Снять двойные пробелы-переносы, но между разделами добавить по два
  text = text.replace(/\n{3,}/g, '\n\n');
  // 6. Ясные абзацы: после раздела "====== ... ======" всегда двойной перенос
  text = text.replace(/(=+\s.+?=+)\n?/g, '$1\n\n');
  // 7. Снять лишние пробелы по краям
  text = text.trim();

  return text;
}

const reply = $input.first().json.choices[0].message.content;
const output = reply.split('</think>');
const reasoning = output[0].replace('<think>', '').trim();
let company_research = output[1] ? output[1].trim() : '';

// Slack-friendly format:
company_research = markdownToSlack(company_research);

return {
  reasoning: markdownToSlack(reasoning),
  company_research,
  raw_reply: reply
};

